appsmith.onReady(() => {
  appsmith.onModelChange(model => {
    const rawData = model.cookies || {};
    const components = rawData.components || {};
    const summary = components.summary || {};
    const byType = summary.by_type || {};
    const byProvider = summary.by_provider || {};
    const crossFileData = rawData.cross_file || {};
    const crossings = rawData.crossings || {};
    const crossingList = crossings.crossings || [];

    // =====================================================================
    // CONFIG — the ONLY values not present in the scan data (presentation /
    // display policy). The exposure index itself uses NO weighting coefficients.
    // =====================================================================
    const CONFIG = {
      indexCap: 100,
      indexThresholds: {
        high: 75,
        medium: 40
      },
      indexColors: {
        high: '#c0392b',
        medium: '#f39c12',
        low: '#27ae60'
      },
      badgeBySeverity: {
        critical: 'badge-critical',
        high: 'badge-warning',
        medium: 'badge-warning',
        low: 'badge-warning'
      },
      badgeDefault: 'badge-warning',
      severityOrder: {
        critical: 0,
        high: 1,
        medium: 2,
        low: 3
      },
      maxActionRows: 5,
      okColor: '#27ae60',
      emptyFindings: 'No critical execution dependencies or boundary violations detected.',
      emptyActions: 'No immediate actions required.',
      // Serialization provider names excluded from the active-vendor tally.
      serializationTypes: ['Pickle', 'Joblib', 'H5', 'PT', 'Safetensors']
    };

    // --- Helpers ---------------------------------------------------------
    const fmtCat = s => String(s || '').split('_').map(w => w.length <= 3 ? w.toUpperCase() : w.charAt(0).toUpperCase() + w.slice(1)).join(' ');
    const cap = s => s ? s.charAt(0).toUpperCase() + s.slice(1).toLowerCase() : s;
    const sevRank = s => CONFIG.severityOrder[String(s || '').toLowerCase()] ?? 99;
    const fmtProviders = obj => Object.entries(obj || {}).map(([k, v]) => `${k} (${Array.isArray(v) ? v.length : v})`).join(', ');

    // --- 1. Top-Level Metrics (all wired to the scan) --------------------
    const boundaryCrossings = crossFileData.ai_boundaries || 0;
    const eligibilityViolations = crossings.prohibited_count || 0;
    const undeclaredComponents = (byType.llm_framework?.count || 0) + (byType.agent?.count || 0);
    const artifactCount = byType.model_artifact?.count || 0;
    let activeVendorCount = 0;
    Object.keys(byProvider).forEach(name => {
      if (!CONFIG.serializationTypes.includes(name) && name !== 'Various') {
        activeVendorCount++;
      }
    });

    // Overall Exposure Index — raw, unweighted sum of the five underlying counts,
    // capped at 100. No coefficients: each item contributes its own count.
    //   boundary + vendors + framework + artifact + eligibility
    const rawScore = boundaryCrossings + activeVendorCount + undeclaredComponents + artifactCount + eligibilityViolations;
    const indexScore = Math.min(CONFIG.indexCap, rawScore);

    // KPI cards
    document.getElementById('exec-exposure-index').innerText = `${indexScore}/${CONFIG.indexCap}`;
    document.getElementById('exec-boundary-crossings').innerText = boundaryCrossings;
    document.getElementById('exec-violations').innerText = eligibilityViolations;
    document.getElementById('exec-artifacts').innerText = artifactCount;
    const indexEl = document.getElementById('exec-exposure-index');
    if (indexScore > CONFIG.indexThresholds.high) indexEl.style.color = CONFIG.indexColors.high;else if (indexScore > CONFIG.indexThresholds.medium) indexEl.style.color = CONFIG.indexColors.medium;else indexEl.style.color = CONFIG.indexColors.low;

    // --- 2. Executive Findings (every specific derived from the scan) ----
    const findingsList = document.getElementById('findings-list');
    findingsList.innerHTML = '';
    const findings = [];
    const prohibited = crossingList.filter(c => c.ai_eligibility === 'prohibited');
    if (prohibited.length > 0) {
      const locs = prohibited.map(c => `${fmtCat(c.data_category)} at ${c.file}:${c.line}`).join('; ');
      findings.push(`<strong>Prohibited Data Flow:</strong> ${prohibited.length} flow(s) blocked by policy — ${locs}.`);
    }
    const byCategory = crossings.by_category || {};
    if ((crossings.total_crossings || 0) > 0 && Object.keys(byCategory).length > 0) {
      const catList = Object.entries(byCategory).map(([k, v]) => `${fmtCat(k)} (${v})`).join(', ');
      findings.push(`<strong>Sensitive Data Crossings:</strong> ${crossings.total_crossings} flow(s) carry restricted data into AI boundaries — by category: ${catList}.`);
    }
    const byBoundary = crossings.by_boundary || {};
    if (boundaryCrossings > 0 || Object.keys(byBoundary).length > 0) {
      const bnames = Object.keys(byBoundary).map(fmtCat).join(', ') || 'n/a';
      findings.push(`<strong>Boundary Exposure:</strong> ${boundaryCrossings} AI boundary node(s) detected; sensitive data observed at: ${bnames}.`);
    }
    if (artifactCount > 0) {
      const artProv = fmtProviders(byType.model_artifact?.providers);
      findings.push(`<strong>Supply Chain Risk:</strong> ${artifactCount} model artifact(s) using serialization formats exposed to code execution — ${artProv}.`);
    }
    if (undeclaredComponents > 0) {
      const govNames = [...Object.keys(byType.llm_framework?.providers || {}), ...Object.keys(byType.agent?.providers || {})].join(', ') || 'n/a';
      findings.push(`<strong>Governance Drift:</strong> ${undeclaredComponents} undeclared framework/agent component(s) require policy mapping — ${govNames}.`);
    }
    if (findings.length === 0) {
      findingsList.innerHTML = `<li style="color: ${CONFIG.okColor};">${CONFIG.emptyFindings}</li>`;
    } else {
      findings.forEach(f => {
        const li = document.createElement('li');
        li.innerHTML = f;
        findingsList.appendChild(li);
      });
    }

    // --- 3. High Priority Action Items (driven entirely by crossings) ----
    const tbody = document.getElementById('exec-table-body');
    tbody.innerHTML = '';
    const actionItems = crossingList.slice().sort((a, b) => sevRank(a.severity) - sevRank(b.severity)).slice(0, CONFIG.maxActionRows).map(c => ({
      cat: fmtCat(c.data_category) + (c.ai_eligibility ? ` (${c.ai_eligibility})` : ''),
      ctx: `${c.file}:${c.line}`,
      severity: cap(c.severity),
      badge: CONFIG.badgeBySeverity[String(c.severity || '').toLowerCase()] || CONFIG.badgeDefault,
      action: c.recommendation || '—'
    }));
    if (actionItems.length === 0) {
      tbody.innerHTML = `<tr><td colspan="4" style="text-align: center;">${CONFIG.emptyActions}</td></tr>`;
      return;
    }
    actionItems.forEach(item => {
      const tr = document.createElement('tr');
      const tdCat = document.createElement('td');
      tdCat.innerHTML = `<strong>${item.cat}</strong>`;
      const tdCtx = document.createElement('td');
      const code = document.createElement('code');
      code.textContent = item.ctx;
      tdCtx.appendChild(code);
      const tdSeverity = document.createElement('td');
      const span = document.createElement('span');
      span.className = `badge ${item.badge}`;
      span.textContent = item.severity;
      tdSeverity.appendChild(span);
      const tdAction = document.createElement('td');
      tdAction.textContent = item.action;
      tr.appendChild(tdCat);
      tr.appendChild(tdCtx);
      tr.appendChild(tdSeverity);
      tr.appendChild(tdAction);
      tbody.appendChild(tr);
    });
  });
});

